// Fire-and-forget impact effect
#include "NiagaraFunctionLibrary.h"
#include "NiagaraComponent.h"

void AMyWeapon::SpawnImpactEffect(FVector Location, FVector Normal) {
    UNiagaraComponent* NComp = UNiagaraFunctionLibrary::SpawnSystemAtLocation(
        GetWorld(), ImpactNiagaraSystem, Location,
        Normal.Rotation(), FVector(1.f), true, true // bAutoDestroy, bAutoActivate
    );
    if (NComp) {
        NComp->SetVariableVec3(TEXT("ImpactNormal"), Normal);
        NComp->SetVariableFloat(TEXT("ImpactForce"), 500.f);
    }
}

// Persistent component on an actor
UPROPERTY(VisibleAnywhere)
UNiagaraComponent* ThrusterFX;

AMyShip::AMyShip() {
    ThrusterFX = CreateDefaultSubobject<UNiagaraComponent>(TEXT("ThrusterFX"));
    ThrusterFX->SetupAttachment(RootComponent);
    ThrusterFX->bAutoActivate = false;
}

void AMyShip::EngageThrusters() {
    ThrusterFX->Activate();
    ThrusterFX->SetVariableFloat(TEXT("ThrustPower"), CurrentThrust);
}
